import{_ as t,o as r,c as e,ai as o}from"./chunks/framework.SowO7O0D.js";const c=JSON.parse('{"title":"第十课：均线系统","description":"","frontmatter":{},"headers":[],"relativePath":"guide/10-moving-average.md","filePath":"guide/10-moving-average.md","lastUpdated":0}'),l={name:"guide/10-moving-average.md"};function n(i,a,s,h,d,g){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="第十课-均线系统" tabindex="-1">第十课：均线系统 <a class="header-anchor" href="#第十课-均线系统" aria-label="Permalink to “第十课：均线系统”">​</a></h1><p>均线是技术分析中最常用的工具，简单但非常实用。</p><h2 id="一、什么是均线" tabindex="-1">一、什么是均线？ <a class="header-anchor" href="#一、什么是均线" aria-label="Permalink to “一、什么是均线？”">​</a></h2><p><strong>均线 = 过去N天的平均价格连线</strong></p><table tabindex="0"><thead><tr><th>均线</th><th>含义</th></tr></thead><tbody><tr><td>5日均线（MA5）</td><td>最近5天平均价格</td></tr><tr><td>10日均线（MA10）</td><td>最近10天平均价格</td></tr><tr><td>20日均线（MA20）</td><td>最近20天平均价格</td></tr><tr><td>60日均线（MA60）</td><td>最近60天平均价格</td></tr></tbody></table><blockquote><p>💡 均线就是&quot;趋势线&quot;，帮助你看清楚价格到底是往上还是往下。</p></blockquote><h2 id="二、均线的核心用法" tabindex="-1">二、均线的核心用法 <a class="header-anchor" href="#二、均线的核心用法" aria-label="Permalink to “二、均线的核心用法”">​</a></h2><h3 id="_1-均线多头排列-看涨" tabindex="-1">1. 均线多头排列（看涨） <a class="header-anchor" href="#_1-均线多头排列-看涨" aria-label="Permalink to “1. 均线多头排列（看涨）”">​</a></h3><p>所有均线从上到下依次是：5日 &gt; 10日 &gt; 20日 &gt; 60日</p><p><strong>含义</strong>：短期 &gt; 中期 &gt; 长期，说明股票处于强势上涨趋势。</p><h3 id="_2-均线空头排列-看跌" tabindex="-1">2. 均线空头排列（看跌） <a class="header-anchor" href="#_2-均线空头排列-看跌" aria-label="Permalink to “2. 均线空头排列（看跌）”">​</a></h3><p>所有均线从上到下依次是：60日 &gt; 20日 &gt; 10日 &gt; 5日</p><p><strong>含义</strong>：短期 &lt; 中期 &lt; 长期，说明股票处于下跌趋势。</p><h3 id="_3-均线粘合-变盘信号" tabindex="-1">3. 均线粘合（变盘信号） <a class="header-anchor" href="#_3-均线粘合-变盘信号" aria-label="Permalink to “3. 均线粘合（变盘信号）”">​</a></h3><p>多条均线挤在一起，距离很近</p><p><strong>含义</strong>：市场到了选择方向的时候，可能大涨也可能大跌。</p><h2 id="三、金叉与死叉-最重要的信号" tabindex="-1">三、金叉与死叉（最重要的信号） <a class="header-anchor" href="#三、金叉与死叉-最重要的信号" aria-label="Permalink to “三、金叉与死叉（最重要的信号）”">​</a></h2><h3 id="金叉-买入信号" tabindex="-1">金叉（买入信号） <a class="header-anchor" href="#金叉-买入信号" aria-label="Permalink to “金叉（买入信号）”">​</a></h3><p>短期均线从下往上穿过长期均线</p><p><strong>举例</strong>：5日均线上穿10日均线 = 金叉</p><p><strong>含义</strong>：短期趋势转强，可能开启上涨。</p><h3 id="死叉-卖出信号" tabindex="-1">死叉（卖出信号） <a class="header-anchor" href="#死叉-卖出信号" aria-label="Permalink to “死叉（卖出信号）”">​</a></h3><p>短期均线从上往下穿过长期均线</p><p><strong>举例</strong>：5日均线下穿10日均线 = 死叉</p><p><strong>含义</strong>：短期趋势转弱，可能开始下跌。</p><blockquote><p>💡 <strong>金叉买，死叉卖</strong>是最简单的技术操作策略，但不适合单独使用。</p></blockquote><h2 id="四、均线的支撑与压力" tabindex="-1">四、均线的支撑与压力 <a class="header-anchor" href="#四、均线的支撑与压力" aria-label="Permalink to “四、均线的支撑与压力”">​</a></h2><h3 id="支撑位-撑住不跌" tabindex="-1">支撑位（撑住不跌） <a class="header-anchor" href="#支撑位-撑住不跌" aria-label="Permalink to “支撑位（撑住不跌）”">​</a></h3><p>股价下跌时，碰到均线往往能&quot;撑住&quot;</p><p><strong>原因</strong>：均线代表平均成本，很多人在这个价格买入，亏了不愿意卖，形成支撑。</p><h3 id="压力位-压住不涨" tabindex="-1">压力位（压住不涨） <a class="header-anchor" href="#压力位-压住不涨" aria-label="Permalink to “压力位（压住不涨）”">​</a></h3><p>股价上涨时，碰到均线往往会&quot;压住&quot;</p><p><strong>原因</strong>：之前在均线附近买入的人解套了，想卖，形成压力。</p><h3 id="实操技巧" tabindex="-1">实操技巧 <a class="header-anchor" href="#实操技巧" aria-label="Permalink to “实操技巧”">​</a></h3><ul><li>股价在均线上方 → 偏强</li><li>股价在均线下方 → 偏弱</li><li>股价回踩均线不破 → 可能是买入机会</li><li>股价反弹到均线附近 → 可能是卖出机会</li></ul><h2 id="五、葛兰碧八大法则" tabindex="-1">五、葛兰碧八大法则 <a class="header-anchor" href="#五、葛兰碧八大法则" aria-label="Permalink to “五、葛兰碧八大法则”">​</a></h2><p>这是均线最经典的用法，记住4个买点和4个卖点：</p><h3 id="买点-4个" tabindex="-1">买点（4个） <a class="header-anchor" href="#买点-4个" aria-label="Permalink to “买点（4个）”">​</a></h3><ol><li><strong>均线从下降转平时</strong>，股价上穿均线</li><li><strong>股价回踩均线</strong>，不破均线后反弹</li><li><strong>股价连续上涨后</strong>，回调到均线附近止跌</li><li><strong>股价远离均线</strong>，但均线仍在上行</li></ol><h3 id="卖点-4个" tabindex="-1">卖点（4个） <a class="header-anchor" href="#卖点-4个" aria-label="Permalink to “卖点（4个）”">​</a></h3><ol><li><strong>均线从上升转平时</strong>，股价下穿均线</li><li><strong>股价反弹到均线</strong>，无法突破均线后回落</li><li><strong>股价连续下跌后</strong>，反弹到均线附近滞涨</li><li><strong>股价远离均线</strong>，但均线已走平或下行</li></ol><h2 id="六、均线的局限性" tabindex="-1">六、均线的局限性 <a class="header-anchor" href="#六、均线的局限性" aria-label="Permalink to “六、均线的局限性”">​</a></h2><blockquote><p>⚠️ <strong>均线是滞后指标</strong>，因为它用的是过去的数据。</p></blockquote><ul><li>均线信号<strong>晚于价格</strong>，往往错过最低点和最高点</li><li>震荡行情中，均线<strong>频繁交叉</strong>，假信号很多</li><li>要结合K线形态、成交量、消息面一起用</li></ul><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>某股票5日均线刚刚上穿20日均线形成金叉，但股价还在60日均线下方。你觉得这个时候应该买入吗？</p></blockquote><hr><p><strong>下一课预告</strong>：均线会用了，下一课学习<strong>MACD指标</strong>——判断趋势强弱的工具。</p>',48)])])}const b=t(l,[["render",n]]);export{c as __pageData,b as default};
